SELECT count(*) FROM hm_query.cart_flat

    AND customer_id = #{userId}
    AND state_id = #{stateId}
    AND currency = #{currency}
    AND customer_name LIKE CONCAT('%', #{customerName}, '%')
    AND customer_email LIKE CONCAT('%', #{customerEmail}, '%')
    AND total >= #{minTotal}
    AND total <= #{maxTotal}
    AND created_time >= #{startDate}
    AND created_time <= #{endDate}
    AND (customer_name LIKE CONCAT('%', #{q}, '%') OR customer_email LIKE CONCAT('%', #{q}, '%') OR cart_id LIKE CONCAT('%', #{q}, '%'))

SELECT cart_id as "id", customer_id as "userId", customer_name as "customerName", customer_email as "customerEmail", session_id as "sessionId", subtotal as "subtotal", currency as "currency", coupon_codes as "couponCodes", discount_amount as "discountAmount", total as "total", item_count as "itemCount", expires_at as "expiresAt", notes as "notes", description as "description", state_id as "stateId", flow_id as "flowId", created_time as "createdTime", last_modified_time as "lastModifiedTime", last_modified_by as "lastModifiedBy", created_by as "createdBy", tenant as "tenant", version as "version" FROM hm_query.cart_flat
AND customer_id = #{userId} AND state_id = #{stateId} AND currency = #{currency} AND customer_name LIKE CONCAT('%', #{customerName}, '%') AND customer_email LIKE CONCAT('%', #{customerEmail}, '%') AND total >= #{minTotal} AND total <= #{maxTotal} AND created_time >= #{startDate} AND created_time <= #{endDate} AND (customer_name LIKE CONCAT('%', #{q}, '%') OR customer_email LIKE CONCAT('%', #{q}, '%') OR cart_id LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

